// ─── SDK Configuration ───
export interface ATSCheckerConfig {
  containerSelector: string;
  isDev?: boolean;
  theme?: 'light' | 'dark' | 'auto';
  ctaUrl?: string;
  maxFileSize?: number;
  allowedTypes?: string[];
  recaptchaSiteKey?: string;

  onFileUpload?: (file: File) => void;
  onAnalysisComplete?: (result: AnalysisResult) => void;
  onCTAClick?: (result: AnalysisResult, anonResumeToken: string) => void;
  onError?: (error: Error) => void;
}

// ─── Analysis Result ───
export interface AnalysisResult {
  totalScore: number;
  grade: 'critical' | 'needs_improvement' | 'ats_ready';
  gradeLabel: string;
  formatting: CategoryResult;
  structure: CategoryResult;
  keywords: KeywordResult;
  topIssues: CheckResult[];
}

export interface CategoryResult {
  maxScore: number;
  score: number;
  checks: CheckResult[];
}

export interface CheckResult {
  id: string;
  index: number;
  name: string;
  description: string;
  status: 'pass' | 'fail' | 'warning';
  penalty: number;
  detail?: string;
}

export interface KeywordResult extends CategoryResult {
  mode: 'job_description' | 'default';
  matchedKeywords?: string[];
  missingKeywords?: string[];
  matchPercentage?: number;
}

// ─── ATS Parser Check (from /v3/anon/resume-parser?ats-check=true) ───
export interface ATSParserCheck {
  textExtractable: boolean;
  isResume: boolean;
  hasComplexLayout: boolean;
  jdMatch?: { keywords: string[]; matchedKeywords: string[] };
  contentAnalysis?: { actionVerbs: string[]; hasMetrics: boolean };
}

export interface ParsedResume {
  text: string;
  isReadable: boolean;
  hasComplexLayout: boolean;
  fileSize: number;
  fileType: string;
  fileName: string;
  pageCount: number;
}

// ─── UI State ───
export type Phase = 'input' | 'scanning' | 'report';

export interface ATSCheckerState {
  phase: Phase;
  file: File | null;
  jobDescription: string;
  showJobDescription: boolean;
  analysisResult: AnalysisResult | null;
  anonResumeToken: string | null;
  resumeData: any | null;
  error: string | null;
}

// ─── Constants ───
export const DEFAULT_MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB
export const DEFAULT_CTA_URL = 'https://app.rezi.ai/signup';
export const DEFAULT_ALLOWED_TYPES = [
  'application/pdf',
  'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
];
