// Utility functions for ATS Checker SDK
// Shared utilities are imported from @rezi/sdk-core

import {
  generateId,
  debounce,
  shuffleArray,
  truncate,
  createElement,
  isClickOutside,
  escapeHtml,
  copyToClipboard,
  setSessionData,
  getSessionData,
  setLocalData,
  getLocalData,
  getTodayKey,
  isValidEmail,
  getKeyboardKey,
} from '@rezi/sdk-core';

export class ATSUtils {
  static generateId = generateId;
  static debounce = debounce;
  static createElement = createElement;
  static isClickOutside = isClickOutside;
  static escapeHtml = escapeHtml;
  static copyToClipboard = copyToClipboard;
  static setLocalData = setLocalData;
  static getLocalData = getLocalData;
  static setSessionData = setSessionData;
  static getSessionData = getSessionData;
  static getTodayKey = getTodayKey;
  static isValidEmail = isValidEmail;
  static getKeyboardKey = getKeyboardKey;
  static shuffleArray = shuffleArray;
  static truncate = truncate;

  static formatFileSize(bytes: number): string {
    if (bytes < 1024) return bytes + ' B';
    if (bytes < 1024 * 1024) return (bytes / 1024).toFixed(1) + ' KB';
    return (bytes / (1024 * 1024)).toFixed(1) + ' MB';
  }
}

// Individual exports for convenience
export {
  generateId,
  debounce,
  createElement,
  isClickOutside,
  escapeHtml,
  copyToClipboard,
  setLocalData,
  getLocalData,
  setSessionData,
  getSessionData,
  getTodayKey,
  isValidEmail,
  getKeyboardKey,
  shuffleArray,
};
