export class ScanningView {
  render(parentEl: HTMLElement): void {
    const header = document.createElement('div');
    header.className = 'rac-scanning-header';
    header.innerHTML = `
      <div class="rac-scanning-header-left">
        <i class="fa-duotone fa-solid fa-file-magnifying-glass rac-scanning-header-icon" aria-hidden="true"></i>
        <span class="rac-scanning-header-title">ATS Resume Checker</span>
      </div>
      <button class="rac-btn-scan-another" disabled aria-disabled="true">
        <i class="fa-duotone fa-solid fa-file-arrow-up" aria-hidden="true"></i>
        SCAN ANOTHER RESUME
      </button>
    `;
    parentEl.appendChild(header);

    const body = document.createElement('div');
    body.className = 'rac-scanning-body';
    body.innerHTML = `
      <div class="rac-scanning-loader">
        <svg class="rac-circular-loader-lg" viewBox="0 0 48 48" aria-hidden="true">
          <circle cx="24" cy="24" r="21" fill="none" stroke="#e2e8f0" stroke-width="3"/>
          <circle class="rac-spinner-arc" cx="24" cy="24" r="21" fill="none"
            stroke="#4d70eb" stroke-width="3"
            stroke-dasharray="99 33" stroke-linecap="round"
            transform="rotate(-90 24 24)"/>
        </svg>
        <p class="rac-scanning-label">Scanning your resume</p>
      </div>
    `;
    parentEl.appendChild(body);
  }
}
