import type {
  ATSCheckerConfig,
  ATSCheckerState,
  ATSParserCheck,
  AnalysisResult,
  ParsedResume,
} from '../types';
import {
  DEFAULT_CTA_URL,
  DEFAULT_MAX_FILE_SIZE,
  DEFAULT_ALLOWED_TYPES,
} from '../types';
import { FileUploadZone } from './FileUploadZone';
import { JobDescriptionInput } from './JobDescriptionInput';
import { ScanningView } from './ScanningView';
import { ReportView } from './ReportView';

import { ResumeDataParser } from '../services/ResumeDataParser';
import { RecaptchaService } from '../services/RecaptchaService';
import { ApiClient } from '../services/ApiClient';
import { getApiConfig, getRecaptchaSiteKey } from '../config/api';
import { notify } from '../services/NotificationService';

export class ATSChecker {
  private state: ATSCheckerState = {
    phase: 'input',
    file: null,
    jobDescription: '',
    showJobDescription: false,
    analysisResult: null,
    anonResumeToken: null,
    resumeData: null,
    error: null,
  };

  private container: HTMLElement;

  private apiClient: ApiClient;
  private resumeDataParser: ResumeDataParser;
  private recaptcha: RecaptchaService | null = null;

  // Preserved across renders so user-entered state (selected file, JD text) survives re-renders
  private fileUploadZone?: FileUploadZone;
  private jobDescriptionInput?: JobDescriptionInput;

  constructor(private config: ATSCheckerConfig) {
    const el = document.querySelector<HTMLElement>(config.containerSelector);
    if (!el) {
      throw new Error(
        `[ATSChecker] Container element not found: "${config.containerSelector}"`,
      );
    }
    this.container = el;

    const isDev = config.isDev ?? false;

    const siteKey = config.recaptchaSiteKey ?? getRecaptchaSiteKey(isDev);
    this.recaptcha = new RecaptchaService(siteKey);
    this.recaptcha.loadScript();

    this.resumeDataParser = new ResumeDataParser(isDev);
    this.apiClient = new ApiClient(getApiConfig(isDev), this.recaptcha, isDev);

    this.initialize();
  }

  private initialize(): void {
    if (document.readyState === 'loading') {
      document.addEventListener('DOMContentLoaded', () => this.render());
    } else {
      this.render();
    }
  }

  destroy(): void {
    this.container.innerHTML = '';
    this.fileUploadZone = undefined;
    this.jobDescriptionInput = undefined;
  }

  private setState(partial: Partial<ATSCheckerState>): void {
    this.state = { ...this.state, ...partial };
    this.render();
  }

  private render(): void {
    this.container.innerHTML = '';
    this.container.className = 'rac-checker';

    const card = document.createElement('div');
    card.className = 'rac-card';

    switch (this.state.phase) {
      case 'input':
        this.renderInputPhase(card);
        break;
      case 'scanning':
        this.container.classList.add('rac-checker--report');
        card.classList.add('rac-card--report');
        this.renderScanningPhase(card);
        break;
      case 'report':
        this.container.classList.add('rac-checker--report');
        card.classList.add('rac-card--report');
        this.renderReportPhase(card);
        break;
    }

    this.container.appendChild(card);
  }

  private renderInputPhase(card: HTMLElement): void {
    const uploadContainer = document.createElement('div');
    uploadContainer.className = 'rac-upload-container';

    if (!this.fileUploadZone) {
      this.fileUploadZone = new FileUploadZone(uploadContainer, {
        maxFileSize: this.config.maxFileSize ?? DEFAULT_MAX_FILE_SIZE,
        allowedTypes: this.config.allowedTypes ?? DEFAULT_ALLOWED_TYPES,
        onFileSelected: (file) => this.handleFileSelected(file),
        onFileRemoved: () => {
          this.state.file = null;
          this.updateScanButton();
          this.jobDescriptionInput?.setDisabled(true);
        },
      });
      this.fileUploadZone.render();
      if (this.state.file) {
        this.fileUploadZone.showFileReadyState(this.state.file);
      }
    }

    if (!this.jobDescriptionInput) {
      this.jobDescriptionInput = new JobDescriptionInput(uploadContainer, {
        onJobDescriptionChange: (text) => {
          this.state.jobDescription = text;
        },
        isDisabled: !this.state.file,
      });
      this.jobDescriptionInput.render();
      if (this.state.jobDescription) {
        this.jobDescriptionInput.setValue(this.state.jobDescription);
      }
    }

    const scanBtn = document.createElement('button');
    scanBtn.type = 'button';
    scanBtn.className = 'rac-btn-primary';
    scanBtn.id = 'rac-scan-btn';
    scanBtn.textContent = 'SCAN MY RESUME';
    scanBtn.disabled = !this.state.file;
    if (!this.state.file) {
      scanBtn.setAttribute('aria-disabled', 'true');
      scanBtn.title = 'Upload a resume file to continue';
    }
    scanBtn.addEventListener('click', () => this.handleScan());
    uploadContainer.appendChild(scanBtn);

    card.appendChild(uploadContainer);
  }

  private updateScanButton(): void {
    const scanBtn =
      this.container.querySelector<HTMLButtonElement>('#rac-scan-btn');
    if (!scanBtn) return;
    const enabled = !!this.state.file;
    scanBtn.disabled = !enabled;
    if (enabled) {
      scanBtn.removeAttribute('aria-disabled');
      scanBtn.removeAttribute('title');
    } else {
      scanBtn.setAttribute('aria-disabled', 'true');
      scanBtn.title = 'Upload a resume file to continue';
    }
  }

  private renderScanningPhase(card: HTMLElement): void {
    new ScanningView().render(card);
  }

  private renderReportPhase(card: HTMLElement): void {
    if (!this.state.analysisResult) return;

    new ReportView({
      ctaUrl: this.config.ctaUrl ?? DEFAULT_CTA_URL,
      onCTAClick: () => {
        if (this.state.analysisResult) {
          this.config.onCTAClick?.(
            this.state.analysisResult,
            this.state.anonResumeToken ?? '',
          );
        }
      },
      onReset: () => this.handleReset(),
    }).render(
      card,
      this.state.analysisResult,
      this.state.anonResumeToken,
      this.state.resumeData,
    );
  }

  private handleFileSelected(file: File): void {
    this.state.file = file;
    this.fileUploadZone?.showFileReadyState(file);
    this.updateScanButton();
    this.jobDescriptionInput?.setDisabled(false);
  }

  private async handleScan(): Promise<void> {
    if (!this.state.file) return;

    const file = this.state.file;

    try {
      this.setState({ phase: 'scanning', error: null });

      this.config.onFileUpload?.(file);

      const jd = this.state.jobDescription.trim() || undefined;

      const resumeResult = await this.resumeDataParser.parseAndGetToken(
        file,
        jd,
      );

      if (!resumeResult || resumeResult.error) {
        const msg =
          resumeResult?.error ??
          'Failed to parse resume data. Please try again.';
        this.fileUploadZone = undefined;
        this.jobDescriptionInput = undefined;
        this.setState({ phase: 'input' });
        notify.error(msg);
        return;
      }

      const { token: anonResumeToken, resumeData, atsCheck } = resumeResult;

      const parsed = this.buildParsedResume(resumeData, file, atsCheck);

      const analysisResult = await this.runATSCheck(parsed, jd, atsCheck);

      this.setState({
        phase: 'report',
        analysisResult,
        anonResumeToken,
        resumeData,
      });

      this.config.onAnalysisComplete?.(analysisResult);
    } catch (error) {
      if (this.config.isDev) {
        console.error('[ATSChecker] Scan failed:', error);
      }

      const msg =
        error instanceof Error
          ? error.message
          : 'Something went wrong. Please try again.';

      this.fileUploadZone = undefined;
      this.jobDescriptionInput = undefined;
      this.setState({ phase: 'input' });
      notify.error(msg);
      this.config.onError?.(error as Error);
    }
  }

  // Builds a ParsedResume for ATS scoring by extracting text from structured resumeData.
  // /v3/anon/resume-parser already parsed the file — no separate parse endpoint needed.
  private buildParsedResume(
    resumeData: any,
    file: File,
    atsCheck?: ATSParserCheck,
  ): ParsedResume {
    // Empty/null resumeData means the parser could not extract text (image-based PDF or corrupted file)
    if (!resumeData) {
      return {
        text: '',
        isReadable: atsCheck?.textExtractable ?? false,
        hasComplexLayout: atsCheck?.hasComplexLayout ?? false,
        fileSize: file.size,
        fileType: file.type,
        fileName: file.name,
        pageCount: 1,
      };
    }

    const parts: string[] = [];

    const c = resumeData.contact || {};
    if (c.name) parts.push(c.name);
    if (c.email) parts.push(c.email);
    if (c.phone) parts.push(c.phone);
    const linkedin =
      typeof c.linkedin === 'string' ? c.linkedin : c.linkedin?.label;
    if (linkedin) parts.push(linkedin);
    const location = [c.location, c.city, c.address].find(
      (v) => typeof v === 'string' && v,
    );
    if (location) parts.push(location);

    const summary = resumeData.summary?.summary ?? resumeData.summary;
    if (typeof summary === 'string' && summary) parts.push(summary);

    const experienceEntries = [
      ...Object.values(resumeData.experience || {}),
      ...Object.values(resumeData.projects || {}),
      ...Object.values(resumeData.project || {}),
    ];
    if (experienceEntries.length > 0) {
      parts.push('Work Experience');
      for (const entry of experienceEntries) {
        const e = entry as any;
        if (e.role || e.title) parts.push(e.role || e.title);
        if (e.company) parts.push(e.company);
        if (e.description) parts.push(e.description);
      }
    }

    const educationEntries = Object.values(resumeData.education || {});
    if (educationEntries.length > 0) {
      parts.push('Education');
      for (const entry of educationEntries) {
        const e = entry as any;
        if (e.qualification || e.degree)
          parts.push(e.qualification || e.degree);
        if (e.institution || e.school) parts.push(e.institution || e.school);
      }
    }

    const skillEntries = Object.values(resumeData.skills || {});
    if (skillEntries.length > 0) {
      parts.push('Skills');
      for (const entry of skillEntries) {
        const e = entry as any;
        if (e.skill) parts.push(e.skill);
      }
    }

    for (const section of ['certification', 'certifications']) {
      for (const entry of Object.values(resumeData[section] || {})) {
        const e = entry as any;
        if (e.certification || e.title || e.name)
          parts.push(e.certification || e.title || e.name);
      }
    }

    const text = parts
      .filter((p) => typeof p === 'string' && p.trim() !== '')
      .join('\n');

    const isReadable = atsCheck?.textExtractable ?? text.length > 0;
    const hasComplexLayout = atsCheck?.hasComplexLayout ?? false;

    return {
      text,
      isReadable,
      hasComplexLayout,
      fileSize: file.size,
      fileType: file.type,
      fileName: file.name,
      pageCount: 1,
    };
  }

  private async runATSCheck(
    parsed: ReturnType<ATSChecker['buildParsedResume']>,
    jd: string | undefined,
    atsCheck?: ATSParserCheck,
  ): Promise<AnalysisResult> {
    type ATSErrorResponse = { error: string; limit?: boolean };
    type ATSResponse = AnalysisResult | ATSErrorResponse;

    const response = await this.apiClient.post<ATSResponse>(
      '/v1/anon/ats-check',
      {
        resumeText: parsed.text,
        fileName: parsed.fileName,
        fileSize: parsed.fileSize,
        isImagePdf: !parsed.isReadable,
        isComplexLayout: parsed.hasComplexLayout,
        isResume: atsCheck?.isResume,
        jobDescription: jd ?? '',
        jdMatch: atsCheck?.jdMatch,
        contentAnalysis: atsCheck?.contentAnalysis,
      },
      'ats_check',
    );

    if ('limit' in response && response.limit === true) {
      throw new Error(
        "You've reached the daily scan limit. Please try again tomorrow.",
      );
    }

    if ('error' in response && response.error) {
      throw new Error(response.error);
    }

    return response as AnalysisResult;
  }

  private handleReset(): void {
    this.fileUploadZone = undefined;
    this.jobDescriptionInput = undefined;

    this.setState({
      phase: 'input',
      file: null,
      jobDescription: '',
      showJobDescription: false,
      analysisResult: null,
      anonResumeToken: null,
      resumeData: null,
      error: null,
    });
  }
}
