export interface FileUploadZoneConfig {
  maxFileSize: number;
  allowedTypes: string[];
  onFileSelected: (file: File) => void;
  onFileRemoved: () => void;
}

export class FileUploadZone {
  private container!: HTMLElement;
  private dropZone!: HTMLElement;
  private fileInput!: HTMLInputElement;
  private selectedFile: File | null = null;

  constructor(
    private readonly parentEl: HTMLElement,
    private readonly config: FileUploadZoneConfig,
  ) {}

  render(): void {
    this.container = this.createElement('div', 'rac-upload-zone-wrapper');
    this.dropZone = this.createDropZone();
    this.fileInput = this.createFileInput();

    this.container.appendChild(this.dropZone);
    this.container.appendChild(this.fileInput);
    this.parentEl.appendChild(this.container);

    this.setupDragDropEvents();
  }

  reset(): void {
    this.selectedFile = null;
    this.fileInput.value = '';
    this.dropZone.classList.remove('has-file', 'dragover', 'uploading');
    this.renderEmptyState();
  }

  getFile(): File | null {
    return this.selectedFile;
  }

  showUploadingState(): void {
    const zone = this.dropZone;
    zone.innerHTML = '';
    zone.classList.remove('has-file', 'dragover');
    zone.classList.add('uploading');

    const spinner = this.createElement('div', 'rac-spinner');
    const text = this.createElement('div', 'rac-upload-uploading-text');
    text.textContent = 'Uploading your resume';

    zone.appendChild(spinner);
    zone.appendChild(text);
  }

  showFileReadyState(file: File): void {
    const zone = this.dropZone;
    zone.innerHTML = '';
    zone.classList.remove('uploading', 'dragover');
    zone.classList.add('has-file');

    // Row: icon + filename side by side
    const row = this.createElement('div', 'rac-upload-file-row');

    const icon = this.createElement('div', 'rac-upload-file-icon');
    icon.innerHTML =
      '<i class="fa-solid fa-file-circle-check" aria-hidden="true"></i>';

    const name = this.createElement('p', 'rac-upload-filename');
    name.textContent = file.name; // textContent prevents XSS

    row.appendChild(icon);
    row.appendChild(name);
    zone.appendChild(row);

    this.selectedFile = file;
  }

  private createDropZone(): HTMLElement {
    const zone = this.createElement('div', 'rac-upload-zone');
    this.renderEmptyStateInto(zone);

    // Click anywhere on the zone to open file picker (not while has-file active,
    // handled by the remove button instead)
    zone.addEventListener('click', (e: MouseEvent) => {
      if (zone.classList.contains('has-file')) return;
      // Don't re-trigger if the click is on the remove button
      if ((e.target as HTMLElement).closest('.rac-file-remove')) return;
      this.fileInput.click();
    });

    return zone;
  }

  private createFileInput(): HTMLInputElement {
    const input = this.createElement<HTMLInputElement>('input', '');
    input.type = 'file';
    input.accept = this.buildAcceptString();
    input.setAttribute('aria-hidden', 'true');
    input.style.display = 'none';

    input.addEventListener('change', () => {
      const file = input.files?.[0] ?? null;
      if (file) {
        this.handleFileSelect(file);
      }
      // Reset input value so the same file can be re-selected after removal
      input.value = '';
    });

    return input;
  }

  private setupDragDropEvents(): void {
    const zone = this.dropZone;

    // Prevent browser from opening the file when dropped outside the zone
    const preventOnBody = (e: Event) => {
      e.preventDefault();
      e.stopPropagation();
    };
    document.body.addEventListener('dragover', preventOnBody, false);
    document.body.addEventListener('drop', preventOnBody, false);

    zone.addEventListener(
      'dragenter',
      (e: DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        if (!zone.classList.contains('has-file')) {
          zone.classList.add('dragover');
        }
      },
      false,
    );

    zone.addEventListener(
      'dragover',
      (e: DragEvent) => {
        // Must call preventDefault to allow drop
        e.preventDefault();
        e.stopPropagation();
        if (!zone.classList.contains('has-file')) {
          zone.classList.add('dragover');
        }
      },
      false,
    );

    zone.addEventListener(
      'dragleave',
      (e: DragEvent) => {
        e.preventDefault();
        e.stopPropagation();
        // Only remove if the pointer truly left the zone (not a child element)
        if (!zone.contains(e.relatedTarget as Node)) {
          zone.classList.remove('dragover');
        }
      },
      false,
    );

    zone.addEventListener(
      'drop',
      (e: DragEvent) => {
        this.handleDrop(e);
      },
      false,
    );
  }

  private handleDrop(e: DragEvent): void {
    e.preventDefault();
    e.stopPropagation();
    this.dropZone.classList.remove('dragover');

    const files = e.dataTransfer?.files;
    if (!files || files.length === 0) return;

    this.handleFileSelect(files[0]);
  }

  private handleFileSelect(file: File): void {
    const validation = this.validateFile(file);
    if (!validation.valid) {
      this.showError(validation.error ?? 'Invalid file.');
      return;
    }

    this.selectedFile = file;
    this.config.onFileSelected(file);
  }

  private validateFile(file: File): { valid: boolean; error?: string } {
    if (!file) {
      return { valid: false, error: 'No file selected.' };
    }

    if (!this.config.allowedTypes.includes(file.type)) {
      const extensions = this.allowedExtensions();
      return {
        valid: false,
        error: `Please upload a ${extensions} file only.`,
      };
    }

    if (file.size > this.config.maxFileSize) {
      const maxMB = this.formatFileSize(this.config.maxFileSize);
      return {
        valid: false,
        error: `File size must be less than ${maxMB}.`,
      };
    }

    return { valid: true };
  }

  private renderEmptyState(): void {
    this.renderEmptyStateInto(this.dropZone);
  }

  private renderEmptyStateInto(zone: HTMLElement): void {
    zone.innerHTML = '';
    zone.removeAttribute('style');

    const icon = this.createElement('div', 'rac-upload-icon');
    icon.innerHTML = '<i class="fa-duotone fa-solid fa-file-arrow-up"></i>';

    const textContainer = this.createElement(
      'div',
      'rac-upload-text-container',
    );

    const heading = this.createElement('p', 'rac-upload-heading');
    heading.innerHTML = '<strong>Upload your resume</strong> or drag and drop';

    const hint = this.createElement('p', 'rac-upload-hint');
    hint.textContent = `PDF, DOCX up to ${this.formatFileSize(this.config.maxFileSize)}`;

    textContainer.appendChild(heading);
    textContainer.appendChild(hint);

    zone.appendChild(icon);
    zone.appendChild(textContainer);
  }

  private showError(message: string): void {
    const existing = this.container.querySelector('.rac-upload-error');
    if (existing) existing.remove();

    const error = this.createElement('p', 'rac-upload-error');
    error.style.cssText =
      'margin: 8px 0 0; font-size: var(--rac-font-size-sm, 14px); ' +
      'color: var(--rac-error, #ef4444);';
    error.setAttribute('role', 'alert');
    error.textContent = message;

    this.container.appendChild(error);

    // Auto-dismiss after 5 seconds
    setTimeout(() => {
      error.remove();
    }, 5000);
  }

  private removeFile(): void {
    this.selectedFile = null;
    this.fileInput.value = '';
    this.dropZone.classList.remove('has-file', 'dragover');
    this.renderEmptyState();
    this.config.onFileRemoved();
  }

  private formatFileSize(bytes: number): string {
    if (bytes === 0) return '0 B';
    const k = 1024;
    const sizes = ['B', 'KB', 'MB', 'GB'];
    const i = Math.floor(Math.log(bytes) / Math.log(k));
    return `${parseFloat((bytes / Math.pow(k, i)).toFixed(1))} ${sizes[i]}`;
  }

  private allowedExtensions(): string {
    const map: Record<string, string> = {
      'application/pdf': 'PDF',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
        'DOCX',
      'application/msword': 'DOC',
      'text/plain': 'TXT',
    };
    const labels = this.config.allowedTypes
      .map((t) => map[t] ?? t)
      .filter(Boolean);
    return labels.length > 0 ? labels.join(' or ') : 'supported file';
  }

  private buildAcceptString(): string {
    // Map MIME types to file extensions so the OS file picker also filters correctly
    const mimeToExt: Record<string, string> = {
      'application/pdf': '.pdf',
      'application/vnd.openxmlformats-officedocument.wordprocessingml.document':
        '.docx',
      'application/msword': '.doc',
      'text/plain': '.txt',
    };

    const extensions = this.config.allowedTypes
      .map((t) => mimeToExt[t] ?? '')
      .filter(Boolean);

    return [...this.config.allowedTypes, ...extensions].join(',');
  }

  private createElement<T extends HTMLElement = HTMLElement>(
    tag: string,
    className: string,
  ): T {
    const el = document.createElement(tag) as T;
    if (className) el.className = className;
    return el;
  }
}
