import type { ApiConfig } from '../config/api';
import type { RecaptchaService } from './RecaptchaService';

export class ApiClient {
  private config: ApiConfig;
  private recaptchaService: RecaptchaService | null;
  private isDev: boolean;

  constructor(
    config: ApiConfig,
    recaptchaService?: RecaptchaService,
    isDev = false,
  ) {
    this.config = config;
    this.recaptchaService = recaptchaService ?? null;
    this.isDev = isDev;
  }

  async post<T>(
    endpoint: string,
    data: Record<string, any>,
    action?: string,
  ): Promise<T> {
    const url = `${this.config.baseUrl}${endpoint}`;
    const { maxRetries, timeout } = this.config;

    // Obtain reCAPTCHA token once before retries
    let recaptchaToken: string | null = null;
    if (this.recaptchaService && action) {
      recaptchaToken = await this.recaptchaService.getToken(action);
      if (!recaptchaToken) {
        console.warn(
          `[ApiClient] ⚠️ reCAPTCHA token is NULL for action="${action}" — X-Recaptcha header will NOT be sent`,
        );
      }
    }

    let lastError: Error | null = null;

    for (let attempt = 0; attempt <= maxRetries; attempt++) {
      try {
        const controller = new AbortController();
        const timeoutId = setTimeout(() => controller.abort(), timeout);

        const headers: Record<string, string> = {
          'Content-Type': 'application/json',
        };

        if (recaptchaToken) {
          headers['X-Recaptcha'] = recaptchaToken;
        }

        const response = await fetch(url, {
          method: 'POST',
          headers,
          body: JSON.stringify(data),
          signal: controller.signal,
        });

        clearTimeout(timeoutId);

        if (!response.ok) {
          const statusCode = response.status;

          // Don't retry on client errors (4xx)
          if (statusCode >= 400 && statusCode < 500) {
            throw new Error(`Client error: ${statusCode}`);
          }

          // Retry on server errors (5xx)
          throw new Error(`Server error: ${statusCode}`);
        }

        const result = await response.json();
        return result as T;
      } catch (error) {
        lastError = error as Error;

        // Don't retry on abort (timeout) or client errors
        if (
          error instanceof Error &&
          (error.name === 'AbortError' ||
            error.message.includes('Client error'))
        ) {
          throw error;
        }

        // Only retry if we have attempts left
        if (attempt < maxRetries) {
          // Exponential backoff: 1s, 2s, 4s...
          const backoffMs = Math.pow(2, attempt) * 1000;
          await this.sleep(backoffMs);
          continue;
        }

        throw lastError;
      }
    }

    throw lastError || new Error('Request failed after retries');
  }

  // No retry logic for file uploads — retrying large payloads significantly increases latency on failure
  async postFormData<T>(
    endpoint: string,
    formData: FormData,
    options?: { timeout?: number; recaptchaToken?: string | null },
  ): Promise<T> {
    const url = `${this.config.baseUrl}${endpoint}`;
    const timeout = options?.timeout ?? this.config.timeout;

    const headers: Record<string, string> = {};

    if (options?.recaptchaToken) {
      headers['X-Recaptcha'] = options.recaptchaToken;
    }

    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), timeout);

    try {
      const response = await fetch(url, {
        method: 'POST',
        headers,
        body: formData,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);

      if (!response.ok) {
        throw new Error(`Request failed: ${response.status}`);
      }

      const result = await response.json();
      return result as T;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}
