export class ResumePreview {
  private container: HTMLElement | null = null;

  constructor(private readonly parentEl: HTMLElement) {}

  render(resumeData: any): void {
    this.reset();
    if (!resumeData) return;

    this.container = document.createElement('div');
    this.container.className = 'rac-resume-template-wrapper';

    const paper = document.createElement('div');
    paper.className = 'rac-resume-paper';

    const contact = resumeData.contact || {};
    const experience = resumeData.experience || {};
    const education = resumeData.education || {};
    const skills = resumeData.skills || {};
    const summary = resumeData.summary?.summary || '';
    const projects = resumeData.projects || resumeData.project || {};
    const certification =
      resumeData.certification ||
      resumeData.certifications ||
      resumeData.certificationData ||
      {};

    // Header: name + contact row
    paper.appendChild(this.renderHeader(contact));
    paper.appendChild(this.renderDivider());

    // Summary
    if (summary) {
      paper.appendChild(
        this.renderSection('Summary', () => {
          const p = document.createElement('p');
          p.className = 'rac-tmpl-summary-text';
          p.textContent = summary;
          return p;
        }),
      );
      paper.appendChild(this.renderDivider());
    }

    // Experience
    const experienceItems = this.sortByIndex(Object.values(experience));
    if (experienceItems.length > 0) {
      paper.appendChild(
        this.renderSection('Experience', () =>
          this.renderExperienceEntries(experienceItems),
        ),
      );
      paper.appendChild(this.renderDivider());
    }

    // Projects
    const projectItems = this.sortByIndex(Object.values(projects));
    if (projectItems.length > 0) {
      paper.appendChild(
        this.renderSection('Projects', () =>
          this.renderExperienceEntries(projectItems),
        ),
      );
      paper.appendChild(this.renderDivider());
    }

    // Education
    const educationItems = this.sortByIndex(Object.values(education));
    if (educationItems.length > 0) {
      paper.appendChild(
        this.renderSection('Education', () =>
          this.renderSimpleEntries(educationItems, 'education'),
        ),
      );
      paper.appendChild(this.renderDivider());
    }

    // Certification
    const certItems = this.sortByIndex(Object.values(certification));
    if (certItems.length > 0) {
      paper.appendChild(
        this.renderSection('Certification', () =>
          this.renderSimpleEntries(certItems, 'certification'),
        ),
      );
      paper.appendChild(this.renderDivider());
    }

    // Skills
    const skillItems = this.sortByIndex(Object.values(skills));
    if (skillItems.length > 0) {
      paper.appendChild(
        this.renderSection('Skills', () => this.renderSkillEntries(skillItems)),
      );
    }

    this.container.appendChild(paper);
    this.parentEl.appendChild(this.container);
  }

  reset(): void {
    if (this.container && this.container.parentNode === this.parentEl) {
      this.parentEl.removeChild(this.container);
    }
    this.container = null;
  }

  // ── Private renderers ──────────────────────────────────────────────────────

  private renderHeader(contact: any): HTMLElement {
    const header = document.createElement('div');
    header.className = 'rac-tmpl-header';

    if (contact.name) {
      const name = document.createElement('p');
      name.className = 'rac-tmpl-name';
      name.textContent = contact.name;
      header.appendChild(name);
    }

    const contactItems: Array<{
      icon: string;
      value: string;
      brand?: boolean;
    }> = [];
    const location = contact.location || contact.address || contact.city;
    if (location) contactItems.push({ icon: 'location-dot', value: location });
    if (contact.email)
      contactItems.push({ icon: 'envelope', value: contact.email });
    if (contact.phone)
      contactItems.push({ icon: 'mobile-screen-button', value: contact.phone });
    const linkedin = this.formatContactValue(contact.linkedin);
    if (linkedin)
      contactItems.push({ icon: 'linkedin', value: linkedin, brand: true });

    if (contactItems.length > 0) {
      const row = document.createElement('div');
      row.className = 'rac-tmpl-contact-row';
      contactItems.forEach(({ icon, value, brand }) => {
        const item = document.createElement('div');
        item.className = 'rac-tmpl-contact-item';

        const i = document.createElement('i');
        i.className = brand
          ? `fa-brands fa-${icon} rac-tmpl-contact-icon`
          : `fa-solid fa-${icon} rac-tmpl-contact-icon`;
        i.setAttribute('aria-hidden', 'true');

        const span = document.createElement('span');
        span.className = 'rac-tmpl-contact-text';
        span.textContent = value;

        item.appendChild(i);
        item.appendChild(span);
        row.appendChild(item);
      });
      header.appendChild(row);
    }

    return header;
  }

  private renderDivider(): HTMLElement {
    const hr = document.createElement('hr');
    hr.className = 'rac-tmpl-divider';
    return hr;
  }

  private renderSection(
    title: string,
    renderContent: () => HTMLElement,
  ): HTMLElement {
    const section = document.createElement('div');
    section.className = 'rac-tmpl-section';

    const headerEl = document.createElement('div');
    headerEl.className = 'rac-tmpl-section-header';
    const titleEl = document.createElement('p');
    titleEl.className = 'rac-tmpl-section-title';
    titleEl.textContent = title;
    headerEl.appendChild(titleEl);
    section.appendChild(headerEl);

    section.appendChild(renderContent());
    return section;
  }

  private renderExperienceEntries(items: any[]): HTMLElement {
    const entries = document.createElement('div');
    entries.className = 'rac-tmpl-entries';

    items.forEach((item: any) => {
      const entry = document.createElement('div');
      entry.className = 'rac-tmpl-entry';

      const parts = [
        item.role || item.title,
        item.company,
        item.location,
        item.duration,
      ].filter(Boolean);

      const titleEl = document.createElement('p');
      titleEl.className = 'rac-tmpl-entry-title';
      titleEl.textContent = parts.join(' | ') || 'Experience';
      entry.appendChild(titleEl);

      const bullets = this.splitBullets(item.description);
      if (bullets.length > 0) {
        const ul = document.createElement('ul');
        ul.className = 'rac-tmpl-bullets';
        bullets.forEach((bullet) => {
          const li = document.createElement('li');
          const span = document.createElement('span');
          span.textContent = bullet;
          li.appendChild(span);
          ul.appendChild(li);
        });
        entry.appendChild(ul);
      }

      entries.appendChild(entry);
    });

    return entries;
  }

  private renderSimpleEntries(
    items: any[],
    type: 'education' | 'certification',
  ): HTMLElement {
    const entries = document.createElement('div');
    entries.className = 'rac-tmpl-simple-entries';

    items.forEach((item: any) => {
      const entry = document.createElement('div');
      entry.className = 'rac-tmpl-simple-entry';

      let parts: string[];
      if (type === 'education') {
        parts = [
          item.qualification || item.degree,
          item.institution || item.university || item.school,
          item.location,
          item.duration || item.date || item.year,
        ].filter(Boolean);
      } else {
        parts = [
          item.certification || item.title || item.name,
          item.institution || item.issuer || item.organization,
          item.location,
          item.duration || item.date || item.year,
        ].filter(Boolean);
      }

      const titleEl = document.createElement('p');
      titleEl.className = 'rac-tmpl-entry-title';
      titleEl.textContent = parts.join(' | ');
      entry.appendChild(titleEl);

      entries.appendChild(entry);
    });

    return entries;
  }

  private renderSkillEntries(items: any[]): HTMLElement {
    const entries = document.createElement('div');
    entries.className = 'rac-tmpl-simple-entries';

    items.forEach((item: any) => {
      if (!item?.skill) return;
      const p = document.createElement('p');
      p.className = 'rac-tmpl-entry-title';
      p.textContent = item.skill;
      entries.appendChild(p);
    });

    return entries;
  }

  // ── Utilities ──────────────────────────────────────────────────────────────

  private sortByIndex(items: any[]): any[] {
    return items
      .filter((item) => item && typeof item === 'object')
      .sort((a, b) => (a?.index ?? 999) - (b?.index ?? 999));
  }

  private decodeHtmlEntities(text: string): string {
    const textarea = document.createElement('textarea');
    textarea.innerHTML = text;
    return textarea.value;
  }

  private splitBullets(text: unknown): string[] {
    return this.decodeHtmlEntities(String(text || ''))
      .replace(/\r/g, '\n')
      .split('\n')
      .map((line) => line.replace(/^[•\-\*]\s*/, '').trim())
      .filter(Boolean);
  }

  private formatContactValue(value: any): string {
    if (!value) return '';
    if (typeof value === 'string') return value;
    if (typeof value === 'object') {
      return value.label || value.value || '';
    }
    return '';
  }
}
