interface CheckResult {
  id: string;
  name: string;
  description: string;
  status: 'pass' | 'fail' | 'warning';
  penalty: number;
  detail?: string;
}

export class CheckItem {
  static render(check: CheckResult): HTMLElement {
    const item = document.createElement('div');
    item.className = 'rac-check-item';
    item.dataset['checkId'] = check.id;

    const icon = document.createElement('span');
    icon.className = `rac-check-icon rac-status-${check.status}`;
    icon.setAttribute('aria-hidden', 'true');
    icon.innerHTML = CheckItem.getIcon(check.status);
    item.appendChild(icon);

    const content = document.createElement('div');
    content.className = 'rac-check-content';

    const name = document.createElement('div');
    name.className = 'rac-check-name';
    name.textContent = check.name;
    content.appendChild(name);

    const detailText = (check.detail ?? check.description ?? '').trim();
    if (detailText) {
      const detail = document.createElement('div');
      detail.className = 'rac-check-detail';
      detail.textContent = detailText;
      content.appendChild(detail);
    }

    item.appendChild(content);

    const penalty = document.createElement('span');
    penalty.className = `rac-check-penalty ${check.status}`;
    penalty.textContent = CheckItem.getPenaltyText(check);
    item.appendChild(penalty);

    return item;
  }

  private static getIcon(status: 'pass' | 'fail' | 'warning'): string {
    const faAvailable =
      typeof window !== 'undefined' &&
      typeof (window as unknown as Record<string, unknown>)['FontAwesome'] !==
        'undefined';

    if (faAvailable) {
      switch (status) {
        case 'pass':
          return '<i class="fas fa-check-circle"></i>';
        case 'fail':
          return '<i class="fas fa-times-circle"></i>';
        case 'warning':
          return '<i class="fas fa-exclamation-triangle"></i>';
      }
    }

    switch (status) {
      case 'pass':
        return '&#x2705;'; // ✅
      case 'fail':
        return '&#x274C;'; // ❌
      case 'warning':
        return '&#x26A0;&#xFE0F;'; // ⚠️
    }
  }

  private static getPenaltyText(check: CheckResult): string {
    if (check.status === 'pass') {
      return 'Pass';
    }
    return `-${check.penalty} pts`;
  }
}
