interface JobDescriptionInputConfig {
  onJobDescriptionChange: (text: string) => void;
  isDisabled?: boolean;
}

const JD_MAX_LENGTH = 5000;

export class JobDescriptionInput {
  private container!: HTMLElement;
  private textarea!: HTMLTextAreaElement;
  private header!: HTMLElement;
  private charWarning!: HTMLElement;
  private isExpanded: boolean = false;
  private isDisabled: boolean;
  private debounceTimer: ReturnType<typeof setTimeout> | null = null;

  constructor(
    private readonly parentEl: HTMLElement,
    private readonly config: JobDescriptionInputConfig,
  ) {
    this.isDisabled = config.isDisabled ?? false;
  }

  render(): void {
    this.container = document.createElement('div');
    this.container.className = 'rac-jd-section';

    if (this.isDisabled) {
      this.container.classList.add('disabled');
    }

    this.header = this.createHeader();
    const content = this.createContent();

    this.container.appendChild(this.header);
    this.container.appendChild(content);
    this.parentEl.appendChild(this.container);
  }

  getText(): string {
    return this.textarea ? this.textarea.value : '';
  }

  reset(): void {
    if (this.isExpanded) {
      this.isExpanded = false;
      this.container.classList.remove('expanded');
      this.header.setAttribute('aria-expanded', 'false');
    }

    if (this.textarea) {
      this.textarea.value = '';
    }

    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
      this.debounceTimer = null;
    }
  }

  setDisabled(disabled: boolean): void {
    this.isDisabled = disabled;
    this.container.classList.toggle('disabled', disabled);
  }

  setValue(text: string): void {
    if (this.textarea) {
      this.textarea.value = text;
    }
  }

  private createHeader(): HTMLElement {
    const header = document.createElement('div');
    header.className = 'rac-jd-header';
    header.setAttribute('role', 'button');
    header.setAttribute('tabindex', '0');
    header.setAttribute('aria-expanded', 'false');
    header.setAttribute('aria-label', 'Toggle job description input');

    const iconSpan = document.createElement('span');
    iconSpan.className = 'rac-jd-icon';
    const briefcaseIcon = document.createElement('i');
    briefcaseIcon.className = 'fa-duotone fa-solid fa-briefcase';
    briefcaseIcon.setAttribute('aria-hidden', 'true');
    iconSpan.appendChild(briefcaseIcon);

    const labelSpan = document.createElement('span');
    labelSpan.className = 'rac-jd-label';
    labelSpan.appendChild(document.createTextNode('Add Job Description '));
    const subSpan = document.createElement('span');
    subSpan.className = 'rac-jd-label-sub';
    subSpan.textContent = '(recommended)';
    labelSpan.appendChild(subSpan);

    const chevronSpan = document.createElement('span');
    chevronSpan.className = 'rac-jd-chevron';
    const chevronIcon = document.createElement('i');
    chevronIcon.className = 'fa-solid fa-chevron-down';
    chevronIcon.setAttribute('aria-hidden', 'true');
    chevronSpan.appendChild(chevronIcon);

    header.appendChild(iconSpan);
    header.appendChild(labelSpan);
    header.appendChild(chevronSpan);

    header.addEventListener('click', () => {
      if (!this.isDisabled) {
        this.handleToggle();
      }
    });

    // Keyboard accessibility — Space / Enter activate the toggle.
    header.addEventListener('keydown', (e: KeyboardEvent) => {
      if ((e.key === ' ' || e.key === 'Enter') && !this.isDisabled) {
        e.preventDefault();
        this.handleToggle();
      }
    });

    return header;
  }

  private createContent(): HTMLElement {
    const content = document.createElement('div');
    content.className = 'rac-jd-content';

    const wrapper = document.createElement('div');
    wrapper.className = 'rac-jd-textarea-wrapper';

    const textarea = this.createTextArea();
    this.textarea = textarea;

    const helper = document.createElement('p');
    helper.className = 'rac-jd-helper-text';
    helper.textContent =
      'Used to check how well your resume matches the required skills and keywords.';

    const charWarning = document.createElement('p');
    charWarning.className = 'rac-jd-char-warning';
    charWarning.textContent = `Job descriptions are limited to ${JD_MAX_LENGTH.toLocaleString()} characters.`;
    charWarning.hidden = true;
    this.charWarning = charWarning;

    wrapper.appendChild(textarea);
    wrapper.appendChild(charWarning);
    wrapper.appendChild(helper);
    content.appendChild(wrapper);
    return content;
  }

  private createTextArea(): HTMLTextAreaElement {
    const textarea = document.createElement('textarea');
    textarea.className = 'rac-jd-textarea';
    textarea.placeholder = 'Job description';
    textarea.setAttribute('aria-label', 'Job description');
    textarea.setAttribute('rows', '6');
    textarea.setAttribute('maxlength', String(JD_MAX_LENGTH));

    textarea.addEventListener('input', () => this.handleInput());

    return textarea;
  }

  private handleToggle(): void {
    this.isExpanded = !this.isExpanded;
    this.container.classList.toggle('expanded', this.isExpanded);
    this.header.setAttribute('aria-expanded', String(this.isExpanded));

    // Focus the textarea when expanding for better keyboard UX.
    if (this.isExpanded && this.textarea) {
      // Allow CSS transition to begin before focusing.
      setTimeout(() => this.textarea.focus(), 50);
    }
  }

  private handleInput(): void {
    const atLimit = this.textarea.value.length >= JD_MAX_LENGTH;
    this.charWarning.hidden = !atLimit;
    this.textarea.classList.toggle('rac-jd-textarea--limit', atLimit);

    if (this.debounceTimer !== null) {
      clearTimeout(this.debounceTimer);
    }

    this.debounceTimer = setTimeout(() => {
      this.debounceTimer = null;
      this.config.onJobDescriptionChange(this.textarea.value);
    }, 300);
  }
}
