interface CheckResult {
  id: string;
  name: string;
  description: string;
  status: 'pass' | 'fail' | 'warning';
  penalty: number;
  detail?: string;
}

interface AnalysisResult {
  totalScore: number;
  grade: 'critical' | 'needs_improvement' | 'ats_ready';
  gradeLabel: string;
  formatting: { maxScore: number; score: number; checks: CheckResult[] };
  structure: { maxScore: number; score: number; checks: CheckResult[] };
  keywords: {
    maxScore: number;
    score: number;
    mode: string;
    checks: CheckResult[];
    matchedKeywords?: string[];
    missingKeywords?: string[];
  };
  topIssues: CheckResult[];
}

interface SectionConfig {
  title: string;
  checks: CheckResult[];
}

export class ReviewList {
  private container: HTMLElement | null = null;

  constructor(private readonly parentEl: HTMLElement) {}

  render(result: AnalysisResult): void {
    this.reset();

    const card = document.createElement('div');
    card.className = 'rac-review-list';
    this.container = card;

    const body = document.createElement('div');
    body.className = 'rac-review-body';

    const sections: SectionConfig[] = [
      { title: 'Critical Formatting', checks: result.formatting.checks },
      { title: 'Structural Integrity', checks: result.structure.checks },
      { title: 'Keywords and Context', checks: result.keywords.checks },
    ];

    sections.forEach(({ title, checks }) => {
      body.appendChild(this.renderSectionHeader(title));

      const issues = checks.filter((c) => c.status !== 'pass');
      if (issues.length > 0) {
        body.appendChild(this.renderImprovements(issues));
      }
    });

    card.appendChild(body);
    this.parentEl.appendChild(card);
  }

  reset(): void {
    if (this.container && this.container.parentNode === this.parentEl) {
      this.parentEl.removeChild(this.container);
    }
    this.container = null;
  }

  private renderSectionHeader(title: string): HTMLElement {
    const header = document.createElement('div');
    header.className = 'rac-review-section-header';

    const label = document.createElement('div');
    label.className = 'rac-review-section-label';

    const text = document.createElement('p');
    text.className = 'rac-review-section-title';
    text.textContent = title;
    label.appendChild(text);

    header.appendChild(label);
    return header;
  }

  private renderImprovements(checks: CheckResult[]): HTMLElement {
    const container = document.createElement('div');
    container.className = 'rac-review-improvements';

    checks.forEach((check, index) => {
      container.appendChild(this.renderItem(check, index === 0));
    });

    return container;
  }

  private renderItem(check: CheckResult, isFirst: boolean): HTMLElement {
    const item = document.createElement('div');
    item.className = 'rac-review-item';
    if (isFirst) item.classList.add('active');

    const iconWrapper = document.createElement('div');
    iconWrapper.className = 'rac-review-item-icon';
    iconWrapper.setAttribute('aria-hidden', 'true');

    const iconEl = document.createElement('span');
    iconEl.className = `rac-review-icon-el rac-review-icon-${check.status}`;
    iconEl.innerHTML = this.getIcon();
    iconWrapper.appendChild(iconEl);
    item.appendChild(iconWrapper);

    const content = document.createElement('div');
    content.className = 'rac-review-item-content';

    const detailText = (check.detail ?? check.description ?? '').trim();
    const hasDetail = detailText.length > 0;

    const labelRow = document.createElement('div');
    labelRow.className = 'rac-review-item-label-row';

    const label = document.createElement('p');
    label.className = hasDetail
      ? 'rac-review-item-label'
      : 'rac-review-item-label rac-review-item-label--truncate';
    label.textContent = check.name;
    labelRow.appendChild(label);
    content.appendChild(labelRow);

    if (hasDetail) {
      const detail = document.createElement('p');
      detail.className = 'rac-review-item-detail';
      detail.textContent = detailText;
      content.appendChild(detail);
    }

    item.appendChild(content);
    return item;
  }

  private getIcon(): string {
    if (this.isFaAvailable()) {
      return '<i class="fa-solid fa-circle-xmark"></i>';
    }
    return '&#x2715;'; // ✕
  }

  private isFaAvailable(): boolean {
    return (
      typeof window !== 'undefined' &&
      typeof (window as unknown as Record<string, unknown>)['FontAwesome'] !==
        'undefined'
    );
  }
}
