import { CheckItem } from './CheckItem';

interface CheckResult {
  id: string;
  name: string;
  description: string;
  status: 'pass' | 'fail' | 'warning';
  penalty: number;
  detail?: string;
}

interface KeywordResult {
  maxScore: number;
  score: number;
  mode: string;
  checks: CheckResult[];
  matchedKeywords?: string[];
  missingKeywords?: string[];
}

interface AnalysisResult {
  totalScore: number;
  grade: 'critical' | 'needs_improvement' | 'ats_ready';
  gradeLabel: string;
  formatting: { maxScore: number; score: number; checks: CheckResult[] };
  structure: { maxScore: number; score: number; checks: CheckResult[] };
  keywords: KeywordResult;
  topIssues: CheckResult[];
}

type ProgressClass = 'critical' | 'warning' | 'good';

function getProgressClass(score: number, maxScore: number): ProgressClass {
  if (maxScore === 0) return 'good';
  const ratio = score / maxScore;
  if (ratio >= 0.8) return 'good';
  if (ratio >= 0.5) return 'warning';
  return 'critical';
}

interface CategoryConfig {
  title: string;
  icon: string;
  score: number;
  maxScore: number;
  checks: CheckResult[];
  extra?: HTMLElement | null;
  expandedByDefault?: boolean;
}

export class AnalysisReport {
  private container: HTMLElement | null = null;

  constructor(private readonly parentEl: HTMLElement) {}

  render(result: AnalysisResult): void {
    this.reset();

    const report = document.createElement('div');
    report.className = 'rac-report';
    this.container = report;

    if (result.topIssues.length > 0) {
      report.appendChild(this.renderIssuesSummary(result.topIssues));
    }

    report.appendChild(
      this.renderCategory({
        title: 'Formatting',
        icon: this.getIcon('formatting'),
        score: result.formatting.score,
        maxScore: result.formatting.maxScore,
        checks: result.formatting.checks,
        expandedByDefault: true,
      }),
    );

    report.appendChild(
      this.renderCategory({
        title: 'Structure',
        icon: this.getIcon('structure'),
        score: result.structure.score,
        maxScore: result.structure.maxScore,
        checks: result.structure.checks,
        expandedByDefault: false,
      }),
    );

    const keywordChips = this.renderKeywordChips(result.keywords);
    report.appendChild(
      this.renderCategory({
        title: 'Keywords',
        icon: this.getIcon('keywords'),
        score: result.keywords.score,
        maxScore: result.keywords.maxScore,
        checks: result.keywords.checks,
        extra: keywordChips,
        expandedByDefault: false,
      }),
    );

    this.parentEl.appendChild(report);
  }

  reset(): void {
    if (this.container && this.container.parentNode === this.parentEl) {
      this.parentEl.removeChild(this.container);
    }
    this.container = null;
  }

  private renderIssuesSummary(topIssues: CheckResult[]): HTMLElement {
    const summary = document.createElement('div');
    summary.className = 'rac-issues-summary';
    summary.setAttribute('role', 'region');
    summary.setAttribute('aria-label', 'Top issues summary');

    const title = document.createElement('div');
    title.className = 'rac-issues-title';
    title.textContent = 'Top Issues';
    summary.appendChild(title);

    topIssues.forEach((issue) => {
      summary.appendChild(CheckItem.render(issue));
    });

    return summary;
  }

  private renderCategory(config: CategoryConfig): HTMLElement {
    const { title, icon, score, maxScore, checks, extra, expandedByDefault } =
      config;

    const category = document.createElement('div');
    category.className = 'rac-category';
    if (expandedByDefault) {
      category.classList.add('expanded');
    }

    const header = document.createElement('div');
    header.className = 'rac-category-header';
    header.setAttribute('role', 'button');
    header.setAttribute('aria-expanded', String(!!expandedByDefault));
    header.setAttribute('tabindex', '0');
    header.setAttribute(
      'aria-label',
      `${title} category, ${score} of ${maxScore} points`,
    );

    const titleEl = document.createElement('span');
    titleEl.className = 'rac-category-title';
    titleEl.innerHTML = `${icon} ${this.escapeHtml(title)}`;

    const rightGroup = document.createElement('div');
    rightGroup.style.cssText = 'display:flex;align-items:center;gap:8px;';

    const scoreEl = document.createElement('span');
    scoreEl.className = 'rac-category-score';
    scoreEl.textContent = `${score}/${maxScore}`;

    const arrow = document.createElement('span');
    arrow.className = 'rac-category-arrow';
    arrow.setAttribute('aria-hidden', 'true');
    // Use FontAwesome when available, otherwise a plain chevron character.
    arrow.innerHTML = this.isFaAvailable()
      ? '<i class="fas fa-chevron-down"></i>'
      : '&#x25BE;'; // ▾

    rightGroup.appendChild(scoreEl);
    rightGroup.appendChild(arrow);

    header.appendChild(titleEl);
    header.appendChild(rightGroup);
    category.appendChild(header);

    category.appendChild(this.renderProgressBar(score, maxScore));

    const body = document.createElement('div');
    body.className = 'rac-category-body';

    checks.forEach((check) => {
      body.appendChild(CheckItem.render(check));
    });

    if (extra) {
      body.appendChild(extra);
    }

    category.appendChild(body);

    const toggle = () => this.handleCategoryToggle(category, header);
    header.addEventListener('click', toggle);
    header.addEventListener('keydown', (e: KeyboardEvent) => {
      if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        toggle();
      }
    });

    return category;
  }

  private renderKeywordChips(result: KeywordResult): HTMLElement | null {
    if (result.mode !== 'job_description') {
      return null;
    }

    const matched = result.matchedKeywords ?? [];
    const missing = result.missingKeywords ?? [];

    if (matched.length === 0 && missing.length === 0) {
      return null;
    }

    const section = document.createElement('div');
    section.className = 'rac-keyword-section';

    const buildRow = (
      label: string,
      keywords: string[],
      chipClass: 'matched' | 'missing',
    ): void => {
      if (keywords.length === 0) return;

      const labelEl = document.createElement('div');
      labelEl.className = 'rac-label';
      labelEl.textContent = label;
      section.appendChild(labelEl);

      const row = document.createElement('div');
      row.className = 'rac-keyword-row';

      keywords.forEach((kw) => {
        const chip = document.createElement('span');
        chip.className = `rac-keyword-chip ${chipClass}`;
        chip.textContent = kw;
        row.appendChild(chip);
      });

      section.appendChild(row);
    };

    buildRow('Matched Keywords', matched, 'matched');
    buildRow('Missing Keywords', missing, 'missing');

    return section;
  }

  private renderProgressBar(score: number, maxScore: number): HTMLElement {
    const bar = document.createElement('div');
    bar.className = 'rac-progress-bar';
    bar.setAttribute('role', 'progressbar');
    bar.setAttribute('aria-valuenow', String(score));
    bar.setAttribute('aria-valuemin', '0');
    bar.setAttribute('aria-valuemax', String(maxScore));
    bar.setAttribute('aria-label', `Score: ${score} of ${maxScore} points`);

    const pct = maxScore > 0 ? Math.round((score / maxScore) * 100) : 0;
    const colorClass = getProgressClass(score, maxScore);

    const fill = document.createElement('div');
    fill.className = `rac-progress-fill ${colorClass}`;
    fill.style.width = '0%'; // start at 0 so CSS transition animates on paint
    requestAnimationFrame(() => {
      fill.style.width = `${pct}%`;
    });

    bar.appendChild(fill);
    return bar;
  }

  private handleCategoryToggle(
    categoryEl: HTMLElement,
    headerEl: HTMLElement,
  ): void {
    const isExpanded = categoryEl.classList.toggle('expanded');
    headerEl.setAttribute('aria-expanded', String(isExpanded));
  }

  private getIcon(category: 'formatting' | 'structure' | 'keywords'): string {
    if (this.isFaAvailable()) {
      switch (category) {
        case 'formatting':
          return '<i class="fas fa-file-alt" aria-hidden="true"></i>';
        case 'structure':
          return '<i class="fas fa-th-list" aria-hidden="true"></i>';
        case 'keywords':
          return '<i class="fas fa-key" aria-hidden="true"></i>';
      }
    }

    switch (category) {
      case 'formatting':
        return '&#x1F537;'; // 🔷
      case 'structure':
        return '&#x1F3D7;&#xFE0F;'; // 🏗️
      case 'keywords':
        return '&#x1F511;'; // 🔑
    }
  }

  private isFaAvailable(): boolean {
    return (
      typeof window !== 'undefined' &&
      typeof (window as unknown as Record<string, unknown>)['FontAwesome'] !==
        'undefined'
    );
  }

  private escapeHtml(str: string): string {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }
}
