// Capture current script URL synchronously before any async code runs.
const _scriptSrc =
  typeof document !== 'undefined'
    ? (document.currentScript as HTMLScriptElement | null)?.src ?? ''
    : '';

function loadSDKStyles(): void {
  if (typeof document === 'undefined') return;
  const STYLE_ID = 'rezi-ats-checker-styles';
  if (document.getElementById(STYLE_ID)) return;

  const link = document.createElement('link');
  link.id = STYLE_ID;
  link.rel = 'stylesheet';
  link.type = 'text/css';

  if (_scriptSrc) {
    const base = _scriptSrc.substring(0, _scriptSrc.lastIndexOf('/') + 1);
    link.href = `${base}rezi-ats-checker.css`;
  } else {
    const sdkScript = Array.from(
      document.querySelectorAll<HTMLScriptElement>('script[src]'),
    ).find((s) => /rezi-ats-checker/.test(s.src));
    const base = sdkScript
      ? sdkScript.src.substring(0, sdkScript.src.lastIndexOf('/') + 1)
      : '';
    link.href = `${base}rezi-ats-checker.css`;
  }

  document.head.appendChild(link);
}

loadSDKStyles();

export * from './components';
export * from './types';
export * from './utils';

function loadFontAwesomeKit() {
  if (typeof document === 'undefined') return;
  const FA_KIT_ID = 'f5adea20e2';
  if (document.querySelector(`script[src*="kit.fontawesome.com/${FA_KIT_ID}"]`))
    return;
  const script = document.createElement('script');
  script.src = `https://kit.fontawesome.com/${FA_KIT_ID}.js`;
  script.crossOrigin = 'anonymous';
  script.async = true;
  document.head.appendChild(script);
}

if (typeof window !== 'undefined') {
  loadFontAwesomeKit();

  import('./components').then((components) => {
    import('./utils').then((utils) => {
      (window as any).ReziATSChecker = {
        ...components,
        ...utils,
      };

      const autoInit = () => {
        const containers = document.querySelectorAll('[data-ats-checker]');
        containers.forEach((container) => {
          if (container.hasAttribute('data-rezi-initialized')) return;

          const isDev = container.getAttribute('data-dev') === 'true';
          const ctaUrl = container.getAttribute('data-cta-url') || undefined;
          const recaptchaKey =
            container.getAttribute('data-recaptcha-key') || undefined;

          new components.ATSChecker({
            containerSelector: '[data-ats-checker]',
            isDev,
            ctaUrl,
            recaptchaSiteKey: recaptchaKey,
          });

          container.setAttribute('data-rezi-initialized', 'true');
        });
      };

      if (document.readyState === 'loading') {
        document.addEventListener('DOMContentLoaded', autoInit);
      } else {
        autoInit();
      }
    });
  });
}
