import type { AnalysisResult, CheckResult } from '../types';
import { ScoreDisplay } from './ScoreDisplay';
import { ResumePreview } from './ResumePreview';

export interface ReportViewConfig {
  ctaUrl: string;
  onCTAClick: () => void;
  onReset: () => void;
}

export class ReportView {
  constructor(private readonly config: ReportViewConfig) {}

  render(
    parentEl: HTMLElement,
    result: AnalysisResult,
    anonResumeToken: string | null,
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    resumeData: any | null,
  ): void {
    const header = document.createElement('div');
    header.className = 'rac-scanning-header';
    header.innerHTML = `
      <div class="rac-scanning-header-left">
        <i class="fa-duotone fa-solid fa-file-magnifying-glass rac-scanning-header-icon" aria-hidden="true"></i>
        <span class="rac-scanning-header-title">ATS Resume Checker</span>
      </div>
    `;
    const scanAnotherBtn = document.createElement('button');
    scanAnotherBtn.type = 'button';
    scanAnotherBtn.className = 'rac-btn-scan-another';
    scanAnotherBtn.innerHTML = `
      <i class="fa-duotone fa-solid fa-file-arrow-up" aria-hidden="true"></i>
      SCAN ANOTHER RESUME
    `;
    scanAnotherBtn.addEventListener('click', () => this.config.onReset());
    header.appendChild(scanAnotherBtn);
    parentEl.appendChild(header);

    const body = document.createElement('div');
    body.className = 'rac-report-body';

    const left = document.createElement('div');
    left.className = 'rac-report-left';

    const scoreCard = document.createElement('div');
    scoreCard.className = 'rac-report-score-card';

    const scoreDisplay = new ScoreDisplay(scoreCard);
    scoreDisplay.render();

    const ctaBtn = document.createElement('a');
    ctaBtn.href = this.buildCTAUrl(anonResumeToken);
    ctaBtn.target = '_blank';
    ctaBtn.rel = 'noopener noreferrer';
    ctaBtn.className = 'rac-btn-fix-rezi';
    const isPerfect = result.totalScore >= 100;
    if (isPerfect) {
      ctaBtn.innerHTML = `<i class="fa-duotone fa-solid fa-sparkles" aria-hidden="true"></i> FIND JOBS IN REZI (FREE)`;
    } else {
      ctaBtn.innerHTML = `<i class="fa-duotone fa-solid fa-sparkles" aria-hidden="true"></i> FIX RESUME IN REZI (FREE)`;
    }
    ctaBtn.addEventListener('click', () => this.config.onCTAClick());
    scoreCard.appendChild(ctaBtn);
    left.appendChild(scoreCard);

    if (result.topIssues.length > 0) {
      left.appendChild(
        this.renderIssuesCard('Top Issues to Fix', result.topIssues),
      );
    } else if (isPerfect) {
      left.appendChild(this.renderPerfectIssuesCard(result));
    }

    left.appendChild(this.renderCategoriesCard(result));

    body.appendChild(left);

    const right = document.createElement('div');
    right.className = 'rac-report-right';

    if (resumeData) {
      const resumePreview = new ResumePreview(right);
      resumePreview.render(resumeData);
    }

    body.appendChild(right);
    parentEl.appendChild(body);

    requestAnimationFrame(() => {
      scoreDisplay.animateScore(result.totalScore);
    });
  }

  private renderIssuesCard(title: string, issues: CheckResult[]): HTMLElement {
    const card = document.createElement('div');
    card.className = 'rac-report-issues-card';

    const titleEl = document.createElement('div');
    titleEl.className = 'rac-report-card-title';
    titleEl.textContent = title;
    card.appendChild(titleEl);

    const list = document.createElement('div');
    list.className = 'rac-report-items-list';

    const sorted = [...issues].sort((a, b) => a.index - b.index);
    sorted.forEach((issue, index) => {
      list.appendChild(this.renderFlatItem(issue, index === 0));
    });

    card.appendChild(list);
    return card;
  }

  private renderPerfectIssuesCard(result: AnalysisResult): HTMLElement {
    const card = document.createElement('div');
    card.className = 'rac-report-issues-card';

    const titleEl = document.createElement('div');
    titleEl.className = 'rac-report-card-title';
    titleEl.textContent = 'Top Issues to Fix';
    card.appendChild(titleEl);

    const list = document.createElement('div');
    list.className = 'rac-report-items-list';
    list.appendChild(this.renderFlatItem(null));
    card.appendChild(list);

    return card;
  }

  private renderCategoriesCard(result: AnalysisResult): HTMLElement {
    const card = document.createElement('div');
    card.className = 'rac-report-categories-card';

    const categories: Array<{ title: string; checks: CheckResult[] }> = [
      { title: 'Critical Formatting', checks: result.formatting.checks },
      { title: 'Structural Integrity', checks: result.structure.checks },
      { title: 'Keywords and Context', checks: result.keywords.checks },
    ];

    categories.forEach(({ title, checks }) => {
      const headerRow = document.createElement('div');
      headerRow.className = 'rac-report-category-row';
      const headerLabel = document.createElement('p');
      headerLabel.className = 'rac-report-category-label';
      headerLabel.textContent = title;
      headerRow.appendChild(headerLabel);
      card.appendChild(headerRow);

      const itemsContainer = document.createElement('div');
      itemsContainer.className = 'rac-report-category-items';

      const sorted = [...checks].sort((a, b) => a.index - b.index);
      const failing = sorted.filter((c) => c.status !== 'pass');
      if (failing.length === 0) {
        itemsContainer.appendChild(this.renderFlatItem(null));
      } else {
        failing.forEach((check) => {
          itemsContainer.appendChild(this.renderFlatItem(check));
        });
      }

      card.appendChild(itemsContainer);
    });

    return card;
  }

  private renderFlatItem(
    check: CheckResult | null,
    defaultOpen = false,
  ): HTMLElement {
    const item = document.createElement('div');
    item.className = 'rac-report-flat-item';

    const iconWrapper = document.createElement('div');
    iconWrapper.className = 'rac-report-flat-icon';
    const i = document.createElement('i');
    if (check === null || check.status === 'pass') {
      i.className =
        'fa-duotone fa-solid fa-circle-check rac-report-flat-icon--pass';
    } else if (check.status === 'warning') {
      i.className =
        'fa-duotone fa-solid fa-circle-xmark rac-report-flat-icon--warning';
    } else {
      i.className =
        'fa-duotone fa-solid fa-circle-xmark rac-report-flat-icon--fail';
    }
    i.setAttribute('aria-hidden', 'true');
    iconWrapper.appendChild(i);

    const body = document.createElement('div');
    body.className = 'rac-report-flat-body';

    const label = document.createElement('p');
    label.className = 'rac-report-flat-label';
    label.textContent = check === null ? 'No issues' : check.name;
    body.appendChild(label);

    const detailText = check
      ? (check.detail ?? check.description ?? '').trim()
      : '';
    if (detailText) {
      const detailWrapper = document.createElement('div');
      detailWrapper.className = 'rac-report-item-detail-wrapper';

      const detailInner = document.createElement('div');
      detailInner.className = 'rac-report-item-detail-inner';

      const detail = document.createElement('p');
      detail.className = 'rac-report-item-detail';
      detail.textContent = detailText;

      detailInner.appendChild(detail);
      detailWrapper.appendChild(detailInner);
      body.appendChild(detailWrapper);

      item.classList.add('rac-report-flat-item--expandable');
      if (defaultOpen) {
        detailWrapper.classList.add('is-open');
        item.classList.add('rac-report-flat-item--active');
      }
      item.addEventListener('click', () => {
        const isOpen = detailWrapper.classList.toggle('is-open');
        item.classList.toggle('rac-report-flat-item--active', isOpen);
      });
    }

    item.appendChild(iconWrapper);
    item.appendChild(body);
    return item;
  }

  private buildCTAUrl(anonResumeToken: string | null): string {
    if (anonResumeToken) {
      const signupResumePath = this.config.ctaUrl.replace(
        /\/signup\/?$/,
        '/signup-resume',
      );
      return `${signupResumePath}?anon_resume_token=${encodeURIComponent(anonResumeToken)}&ref=ats_checker`;
    }
    return `${this.config.ctaUrl}?ref=ats_checker`;
  }
}
