// Reuses existing anon resume endpoints so the CTA handoff can redirect to
// /signup-resume?anon_resume_token={token} and apply resume data instantly on login.

import type { ATSParserCheck } from '../types';

const REZI_FILE_MARKERS = ['rz-v1.2.1', 'rms_v2'] as const;

export interface ParseResult {
  token: string;
  resumeData: any;
  hasComplexLayout: boolean;
  atsCheck?: ATSParserCheck;
  error?: string;
}

export class ResumeDataParser {
  private readonly reziParserUrl: string;
  private readonly nonReziParserUrl: string;
  private readonly tokenUrl: string;

  constructor(private readonly isDev: boolean = false) {
    const base = isDev ? 'https://dev-api.rezi.ai' : 'https://api.rezi.ai';
    this.reziParserUrl = `${base}/v1/anon/resume-metadata-parser`;
    this.nonReziParserUrl = `${base}/v3/anon/resume-parser`;
    this.tokenUrl = `${base}/v1/anon/handle-resume`;
  }

  async parseAndGetToken(
    file: File,
    jobDescription?: string,
  ): Promise<ParseResult | null> {
    try {
      const fileError = await this.validateFileContent(file);
      if (fileError) {
        return {
          token: '',
          resumeData: null,
          hasComplexLayout: false,
          error: fileError,
        };
      }

      const parseResult = await this.parseToResumeData(file, jobDescription);
      if (!parseResult) {
        return {
          token: '',
          resumeData: null,
          hasComplexLayout: false,
          error: 'Failed to parse resume. Please try again.',
        };
      }

      const { data: resumeData, hasComplexLayout, atsCheck } = parseResult;

      // Token is used for the CTA redirect only — don't block ATS analysis on token failure.
      // Image-based PDFs may produce empty resumeData that causes the token endpoint to fail;
      // we still want to proceed so the Text Extractability fail is shown in the report.
      const token = await this.getAnonResumeToken(resumeData);

      return { token: token ?? '', resumeData, hasComplexLayout, atsCheck };
    } catch (error) {
      if (this.isDev) {
        console.warn('[ResumeDataParser] parseAndGetToken failed:', error);
      }
      const msg =
        error instanceof Error
          ? error.message
          : 'Something went wrong while processing your resume.';
      return {
        token: '',
        resumeData: null,
        hasComplexLayout: false,
        error: msg,
      };
    }
  }

  private async parseToResumeData(
    file: File,
    jobDescription?: string,
  ): Promise<{
    data: any;
    hasComplexLayout: boolean;
    atsCheck?: ATSParserCheck;
  } | null> {
    try {
      const isRezi = await this.checkIsReziFile(file);

      if (isRezi) {
        const response = await fetch(this.reziParserUrl, {
          method: 'POST',
          headers: { 'Content-Type': file.type },
          body: file,
        });

        if (!response.ok) {
          throw new Error(`Rezi parser HTTP ${response.status}`);
        }

        const data = await response.json();
        return {
          data: data?.parsedData?.data || null,
          hasComplexLayout: false,
        };
      } else {
        const formData = new FormData();
        formData.append('file', file);
        if (jobDescription) {
          formData.append('jobDescription', jobDescription);
        }

        const response = await fetch(
          `${this.nonReziParserUrl}?ats-check=true`,
          {
            method: 'POST',
            body: formData,
          },
        );

        if (!response.ok) {
          throw new Error(`Non-Rezi parser HTTP ${response.status}`);
        }

        const data = await response.json();
        const atsCheck: ATSParserCheck | undefined =
          data?.atsCheck ?? undefined;

        return {
          data: data?.data || null,
          hasComplexLayout:
            atsCheck?.hasComplexLayout ?? data?.hasComplexLayout === true,
          atsCheck,
        };
      }
    } catch (error) {
      if (this.isDev) {
        console.warn('[ResumeDataParser] parseToResumeData failed:', error);
      }
      return null;
    }
  }

  private async getAnonResumeToken(resumeData: any): Promise<string | null> {
    try {
      const response = await fetch(this.tokenUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(resumeData),
      });

      if (!response.ok) {
        throw new Error(`Token endpoint HTTP ${response.status}`);
      }

      const result = await response.json();
      return result?.token || null;
    } catch (error) {
      if (this.isDev) {
        console.warn('[ResumeDataParser] getAnonResumeToken failed:', error);
      }
      return null;
    }
  }

  // Returns null if file is valid, or an error message if invalid.
  validateFileContent(file: File): Promise<string | null> {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = (e) => {
        const buf = e.target?.result as ArrayBuffer;
        const bytes = new Uint8Array(buf);
        const prefix = String.fromCharCode(...bytes.slice(0, 4));

        const isPDF = prefix.startsWith('%PDF');
        // DOCX is a ZIP — magic bytes PK\x03\x04
        const isDOCX =
          bytes[0] === 0x50 &&
          bytes[1] === 0x4b &&
          bytes[2] === 0x03 &&
          bytes[3] === 0x04;

        if (!isPDF && !isDOCX) {
          resolve(
            'The file does not appear to be a valid PDF or DOCX. Please re-download your resume and try again.',
          );
        } else {
          resolve(null);
        }
      };
      reader.onerror = () => resolve(null); // allow through on read error
      reader.readAsArrayBuffer(file.slice(0, 4));
    });
  }

  private checkIsReziFile(file: File): Promise<boolean> {
    return new Promise((resolve) => {
      const reader = new FileReader();
      reader.onloadend = (e) => {
        const content = e.target?.result as string;
        resolve(REZI_FILE_MARKERS.some((marker) => content?.includes(marker)));
      };
      reader.onerror = () => resolve(false);
      reader.readAsText(file, 'utf-8');
    });
  }
}
