// Injected at build time by webpack DefinePlugin from assets/ellipse.svg
declare const __ELLIPSE_SVG__: string;

export class ScoreDisplay {
  private container!: HTMLElement;
  private indicatorDot!: HTMLDivElement;
  private scoreText!: HTMLElement;
  private gradeLabel!: HTMLElement;

  private animationFrameId: number | null = null;

  // Arc geometry: center at bottom-center of 236×118 container
  // outer R=118, inner R=94.4 → midpoint R=106.2
  private readonly CX = 118;
  private readonly CY = 118;
  private readonly R = 106;

  constructor(private readonly parentEl: HTMLElement) {}

  render(): void {
    this.container = document.createElement('div');
    this.container.className = 'rac-score-display';

    const gaugeWrapper = document.createElement('div');
    gaugeWrapper.className = 'rac-gauge-wrapper';

    // Inline SVG arc image (injected by webpack DefinePlugin)
    const ellipseLayer = document.createElement('div');
    ellipseLayer.className = 'rac-gauge-ellipse-layer';
    ellipseLayer.innerHTML = __ELLIPSE_SVG__;
    gaugeWrapper.appendChild(ellipseLayer);

    // Indicator dot (absolutely positioned, moves based on score)
    const dot = document.createElement('div');
    dot.className = 'rac-gauge-dot';
    this.indicatorDot = dot;
    gaugeWrapper.appendChild(dot);

    // Score + grade text overlay
    const textOverlay = document.createElement('div');
    textOverlay.className = 'rac-gauge-text';

    const scoreEl = document.createElement('div');
    scoreEl.className = 'rac-gauge-score';
    scoreEl.textContent = '0';
    this.scoreText = scoreEl;

    const gradeEl = document.createElement('div');
    gradeEl.className = 'rac-grade-label';
    this.gradeLabel = gradeEl;

    textOverlay.appendChild(scoreEl);
    textOverlay.appendChild(gradeEl);
    gaugeWrapper.appendChild(textOverlay);

    const scaleRow = document.createElement('div');
    scaleRow.className = 'rac-gauge-scale';

    const scaleMin = document.createElement('span');
    scaleMin.textContent = '0';
    const scaleMax = document.createElement('span');
    scaleMax.textContent = '100';

    scaleRow.appendChild(scaleMin);
    scaleRow.appendChild(scaleMax);

    this.container.appendChild(gaugeWrapper);
    this.container.appendChild(scaleRow);
    this.parentEl.appendChild(this.container);

    // Place dot at score 0 (left end)
    this.setDotPosition(0);
  }

  animateScore(targetScore: number): void {
    if (this.animationFrameId !== null) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }

    const clamped = Math.max(0, Math.min(100, targetScore));
    const duration = 1500;
    const startTime = performance.now();

    const animate = (now: number): void => {
      const elapsed = now - startTime;
      const progress = Math.min(elapsed / duration, 1);
      // Ease-out cubic
      const eased = 1 - Math.pow(1 - progress, 3);
      const current = Math.round(eased * clamped);

      this.scoreText.textContent = String(current);
      this.setDotPosition(current);

      if (progress < 1) {
        this.animationFrameId = requestAnimationFrame(animate);
      } else {
        this.animationFrameId = null;
        this.scoreText.textContent = String(clamped);
        this.setDotPosition(clamped);
        this.gradeLabel.textContent = this.getGradeLabel(clamped);
      }
    };

    this.animationFrameId = requestAnimationFrame(animate);
  }

  reset(): void {
    if (this.animationFrameId !== null) {
      cancelAnimationFrame(this.animationFrameId);
      this.animationFrameId = null;
    }
    if (this.scoreText) this.scoreText.textContent = '0';
    if (this.gradeLabel) this.gradeLabel.textContent = '';
    this.setDotPosition(0);
  }

  // score 0 → π (left end), score 50 → π/2 (top), score 100 → 0 (right end)
  private setDotPosition(score: number): void {
    if (!this.indicatorDot) return;
    const angle = Math.PI * (1 - score / 100);
    const x = this.CX + this.R * Math.cos(angle);
    const y = this.CY - this.R * Math.sin(angle);
    this.indicatorDot.style.left = `${x.toFixed(2)}px`;
    this.indicatorDot.style.top = `${Math.min(110, y).toFixed(2)}px`;
  }

  private getGradeLabel(score: number): string {
    if (score >= 80) return 'ATS Ready';
    if (score >= 50) return 'Needs Improvement';
    return 'Critical';
  }
}
