export class CTASection {
  private container!: HTMLElement;

  constructor(
    private readonly parentEl: HTMLElement,
    private readonly config: {
      ctaUrl: string;
      onCTAClick: (tempFileId: string | null) => void;
      onReset: () => void;
    },
  ) {}

  render(tempFileId: string | null, anonResumeToken?: string | null): void {
    // Remove any previously rendered version so render() is idempotent.
    if (this.container) {
      this.container.remove();
    }

    this.container = document.createElement('div');
    this.container.className = 'rac-cta-section';

    const ctaButton = this.createCTAButton(tempFileId, anonResumeToken ?? null);
    const resetRow = this.createResetRow();

    this.container.appendChild(ctaButton);
    this.container.appendChild(resetRow);
    this.parentEl.appendChild(this.container);
  }

  private createCTAButton(
    tempFileId: string | null,
    anonResumeToken: string | null,
  ): HTMLButtonElement {
    const btn = document.createElement('button');
    btn.className = 'rac-btn-cta';
    btn.type = 'button';
    btn.setAttribute('aria-label', 'Fix your resume in Rezi for free');

    const icon = document.createElement('i');
    icon.className = 'fas fa-wrench';
    icon.setAttribute('aria-hidden', 'true');

    const label = document.createElement('span');
    label.textContent = 'Fix Resume in Rezi (Free)';

    btn.appendChild(icon);
    btn.appendChild(label);

    btn.addEventListener('click', () =>
      this.handleCTAClick(tempFileId, anonResumeToken),
    );

    return btn;
  }

  private createResetRow(): HTMLElement {
    const row = document.createElement('div');
    row.className = 'rac-cta-reset';

    const link = document.createElement('button');
    link.className = 'rac-btn-link';
    link.type = 'button';
    link.textContent = 'Upload another resume';
    link.setAttribute('aria-label', 'Start over and upload a different resume');

    link.addEventListener('click', () => this.config.onReset());

    // Keyboard accessibility — Space and Enter both activate the link.
    link.addEventListener('keydown', (e: KeyboardEvent) => {
      if (e.key === ' ' || e.key === 'Enter') {
        e.preventDefault();
        this.config.onReset();
      }
    });

    row.appendChild(link);
    return row;
  }

  // Priority: anonResumeToken → /signup-resume (instant apply) > tempFileId → /signup > plain /signup
  private buildCTAUrl(
    tempFileId: string | null,
    anonResumeToken: string | null,
  ): string {
    if (anonResumeToken) {
      const signupResumePath = this.config.ctaUrl.replace(
        /\/signup\/?$/,
        '/signup-resume',
      );
      return `${signupResumePath}?anon_resume_token=${encodeURIComponent(anonResumeToken)}&ref=ats_checker`;
    }

    const base = `${this.config.ctaUrl}?ref=ats_checker`;
    if (tempFileId !== null && tempFileId.length > 0) {
      return `${base}&import_file_id=${encodeURIComponent(tempFileId)}`;
    }

    return base;
  }

  private handleCTAClick(
    tempFileId: string | null,
    anonResumeToken: string | null,
  ): void {
    this.config.onCTAClick(tempFileId);

    const url = this.buildCTAUrl(tempFileId, anonResumeToken);
    window.open(url, '_blank', 'noopener,noreferrer');
  }
}
